var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그래서, 충성스러운 직원들은 버려 두고 그 쓸모없는 여자랑 둘이 도망쳤단 말이야?","JPN":"それで、献身的な社員たちを見捨てて何の役にも立たない女と二人で逃げたってこと？","ENG":"So you abandoned your loyal employees and ran off with that useless woman?","TWN":"所以你的意思是，你扔下那些忠心耿耿的員工，帶著沒什麼用的女人逃跑嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"사랑의 도피라기엔 너무 볼썽사납네.","JPN":"愛の逃避行というには見苦しいわね。","ENG":"Not exactly the most romantic way to elope, if you ask me.","TWN":"這是什麼一點也不感人的愛情故事？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"목숨 바쳐 나를 지키라고 고용한 놈들이야. 그동안 받아먹은 돈값은 해야지.","JPN":"命をかけて僕を守るために雇われたやつらだ。これまでこっちが払った金の分、働いてもらわないと。","ENG":"I hired those fools to risk their lives to save me. It's time they earned their keep.","TWN":"我花錢請他們來就是要為我擋子彈的，拿錢辦事很正常吧。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"사채꾼 하나도 어떻게 못 하면 해고 사유가 될 테니까.","JPN":"闇金業者の一人も対応できないやつらは解雇されても言い訳できないだろ。","ENG":"If they can't handle some lowly loan shark, they're fired.","TWN":"如果連區區一個高利貸都搞不定，就等著回家吃自己吧。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"상상만 해도 비극적인걸. 병상에 누운 채로 보상 한 푼 못 받고 해고 통지를 받는 풍경이란.","JPN":"想像するだけで悲劇的だわ。病床に伏せたまま補償は\\n1クレジットも支払われず、解雇通知だけを受け取る状況がね。","ENG":"It brings a tear to my eyes to imagine how it'll go down. Getting sacked without so much as a penny to pay their hospital bills.","TWN":"光想就覺得很慘，躺在病床上，沒有得到獎賞，只有收到離職通知。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"뭘 자기는 예외인 것처럼 시시덕거리지?","JPN":"なぜ自分は例外だと思い込んでいるんだ？","ENG":"Save the sarcasm. What makes you think you'll be the exception?","TWN":"你怎麼一副事不關己的樣子？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"모가지가 위험한 건 너도 마찬가지다, 셰나.","JPN":"首になるかもしれないのはお前も同じだ、シェナ。","ENG":"Your career is just as precarious right now, Shena.","TWN":"你以為你的位置很穩嗎，世娜？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"경호실장 주제에 그 빌어먹을 사채꾼이 내 소재를 알아낸 줄도 몰랐다는 게 말이 되나?","JPN":"警護室長のくせに、あのクソ闇金業者が僕の居場所を突き止めたことも知らなかったなんてあり得ないだろ？","ENG":"What kind of a head of security didn't even realize that damn loan shark found my location?","TWN":"身為護衛室長，竟然沒發現她找到我的下落，會不會太誇張？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"말했잖아. 그러게 연구소든 어디든 가면 좀 잘 쓰고 다니라니까.","JPN":"だから言ったでしょ。研究所だけじゃなくて、どこに行ってもちゃんと仮面を被りなさいって。","ENG":"I'd hate to say I told you so… But you really should have kept that mask on.","TWN":"我不是有提醒你嗎～叫你不管是要去研究所，還是去哪裡，面具都要戴好戴滿。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"가면만 쓰고 다녔으면 꼬리가 잡힐 일도 없었을 거 아냐?","JPN":"仮面さえちゃんと被っていれば、感づかれることはなかったじゃない？","ENG":"You wouldn't have had to deal with this if you had kept your face covered.","TWN":"要是你有聽話乖乖戴面具，還會被人家抓到小辮子嗎？你說說看？？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"닥쳐.","JPN":"黙れ。","ENG":"Shut up,","TWN":"閉嘴！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"네 핑계는 질리게 들었어. 내 인내심이 한계에 다다를 때까지 말이야.","JPN":"お前の言い訳はもううんざりだ。こっちは我慢の限界なんだよ。","ENG":"I'm sick and tired of your excuses. I've simply had it with you.","TWN":"我不想再聽你的藉口，不要挑戰我的耐心！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"상부로부터 날 지키라는 지시를 받지 않았나?","JPN":"上層部から僕を守れという指示を受けているだろ？","ENG":"Have you not received the strictest orders from the leadership to protect me?","TWN":"你沒收到上面的指示嗎？叫你好好保護我？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"내 털끝 하나라도 다치면 어떻게 될지는 네가 제일 잘 알고 있을 텐데?","JPN":"僕が怪我でもしたらどうなるか、お前が一番知っているはずだ。","ENG":"You know better than anyone what would happen if there's so much as a scratch on me.","TWN":"萬一傷到我一根寒毛會發生甚麼事，你應該比任何人都清楚吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"같잖은 장난 그만치고 당장 와서 나를 경호해. 계속 그따위로 굴면 상부에 보고하겠어.","JPN":"のらりくらりと逃げずに今すぐこっちで僕を警護しろ。ずっとその調子なら上層部に報告するぞ。","ENG":"Now quit goofing around and come secure me at once. Otherwise, I'll report you to leadership.","TWN":"不要再跟我嘻皮笑臉的，立刻過來保護我！你再這樣我就要跟上面報告！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 어떡할까. 위에다 일러바치면 내 입장이 무척 난처해지는데.","JPN":"フフッ。どうしようかな。上に告げ口されたらとっても困っちゃうわ。","ENG":"Oh my. What should I do? You'll put me in a most difficult situation if you tattle on me.","TWN":"呵呵，我好怕喔，你跟上面打小報告的話，我的處境會變得很困難。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"걱정 마. 그렇게 말할 것 같아서 지금 병력을 데리고 그리로 가는 중이니까.","JPN":"もう心配しないで。そう言われると思って、今兵士たちを連れてそっちに向っている途中よ。","ENG":"Don't worry. I had a feeling you'd say that, so I'm sending troops your way.","TWN":"放心吧，我就怕會這樣，所以現在正帶著人去找你。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"흥……. 끝까지 잘난 척이군.","JPN":"ふん……いつまでも偉そうにしやがって。","ENG":"Hmph… Show off.","TWN":"哼……還在那嘴硬！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"호텔에서 가장 가까운 연구 시설로 가고 있다. 늦지 않게 와라.","JPN":"ホテルから最も近い研究施設に向かっている。遅れずに来い。","ENG":"I'm on my way to the research facility nearest to the hotel. Don't be late.","TWN":"我現在要去離飯店最近的研究設施，你快點過來！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"TWN":"呼……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Whew...","TWN":"親愛的，你要不要休息一下，你看起來好疲憊。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자, 자기야. 쉬어야겠어. 지금 너무 피곤해 보여.","JPN":"ダ、ダーリン。ちょっと休んだほうがいいんじゃない？　すごく疲れた顔してるよ。","ENG":"Aww, babe… You should get some rest. You look exhausted.","TWN":"沒關係～我沒事。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아냐. 나는 괜찮아.","JPN":"いや、僕は平気さ。","ENG":"No. I'm fine.","TWN":"只是……沒想到會再遇到不想見的人，所以有點驚嚇過度。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그냥……. 잊고 싶은 녀석이랑 다시 마주치는 바람에 경황이 없었을 뿐이야.","JPN":"ただ……二度と思い出したくないやつにまた出くわしたせいで、余裕がなくなっただけだ。","ENG":"I just… got a little taken by surprise when I ran into someone I'd rather forget.","TWN":"你是說剛剛那個不良少女吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"아까 그 불량배 말이지?","JPN":"さっきの不良の子のこと？","ENG":"You mean that thug earlier?","TWN":"她到底是誰？劈頭就叫你還錢，她是精神不正常嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"걔 대체 뭐야? 자기한테 다짜고짜 돈을 내놓으라던데, 미친 거 아냐?","JPN":"あの子いったい何なの？　ダーリンにいきなりお金を返せとか言って、頭おかしいんじゃない？","ENG":"What was her deal? She just started harassing you to cough up money. Is she insane?","TWN":"對啊，她從以前就是那樣。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래. 예전부터 그런 녀석이었어.","JPN":"ああ。昔からそんなやつだった。","ENG":"Yes. She was always like that.","TWN":"沒錯，她從以前就是這樣。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"사실……. 사업을 시작하기 전에 사채를 쓴 적이 있거든.","JPN":"実は……今の事業を始める前に、闇金を使ったことがあるんだ。","ENG":"The thing is… I borrowed some money from that loan shark before I started my business.","TWN":"其實……我在設立公司前，曾經借過高利貸。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"사채? 자기 같은 사람이?","JPN":"闇金？　ダーリンみたいなお金持ちが？","ENG":"Loan shark? Why would someone upstanding like you go to a crook like that?","TWN":"高利貸？親愛的還需要借高利貸嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래. 몇 년 전까지만 해도 나는 가난한 학생이었어.","JPN":"ああ。数年前までは僕も貧しい学生だったから。","ENG":"I know, I know. I was but an impoverished student until just a few years ago.","TWN":"沒錯，別看我現在這樣，幾年前我還只是個窮學生。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그리고 연구비를 마련하기 위해서 어쩔 수 없이 그 사채업자한테 돈을 빌리고 말았지.","JPN":"そして研究費用を用意するために、仕方なくあの闇金業者からお金を借りてしまったのさ。","ENG":"I had no choice but to borrow that money for research funding.","TWN":"當時為了籌措研究費，不得已只好向高利貸借錢。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"당시에는 몰랐어. 그렇게까지 끔찍한 놈인 줄 알았더라면…….","JPN":"当時は知らなかったんだ。あんなにひどいやつだと知っていたなら……","ENG":"I had no idea at the time. If I only knew what a monster she was…","TWN":"我當時根本沒想到，竟然會招惹上這麼可怕的傢伙……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기야…….","JPN":"ダーリン……","ENG":"Oh, babe…","TWN":"親愛的……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"기운내. 그런 돈 갚을 필요 하나도 없어. 애초에 전부 불법이잖아.","JPN":"気にしないでね。あんな人から借りたお金は返す必要なんてないよ。そもそも違法なんでしょ。","ENG":"Don't worry. You don't have to pay that thug a single penny. I'm sure it's all illegal anyway.","TWN":"別難過，那這樣根本不需要還錢，因為高利貸本身就是不合法的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"그 사채업자도 진짜 양심없다. 자기가 회사를 세워서 세상에 좋은 일을 얼마나 많이 하는데.","JPN":"あの闇金業者も全然わかってないのね。\\nダーリンが作った会社が今社会にどれだけ貢献しているかも知らないのかしら？","ENG":"That loan shark is such a heartless thug. You've done to this world so much good with your company.","TWN":"那個放高利貸的真的很壞心，也不想想親愛的設立公司後，做了多少好事。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"……고마워. 네가 옆에 없었더라면 어떻게 됐을지, 상상하기도 끔찍해.","JPN":"……ありがとう。君の支えがなかったら今頃僕はどうなっていたのか、想像すらできない。","ENG":"...Thanks. I'd hate to imagine what would have happened if I didn't have you by my side.","TWN":"……謝謝親愛的，我真不敢想像，萬一你不在我身邊會怎樣。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"대표님, 말씀 중에 죄송합니다.","JPN":"代表、お話中に申し訳ございません。","ENG":"Sir, please forgive me for interrupting.","TWN":"代表，抱歉打斷對話。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"호텔에 출동했던 아군과의 교신이 모두 두절되었습니다. 상황이 심각합니다.","JPN":"ホテルに出動した味方との交信がすべて途絶えました。状況は深刻です。","ENG":"But we've lost all contact with our troops at the hotel. It's getting pretty serious.","TWN":"我們派到飯店的人全都聯絡不上，現在情況非常嚴峻。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하아……. 멍청한 놈들.","JPN":"はあ……間抜けばかりだな。","ENG":"Ugh… Those fools.","TWN":"哀……一群沒用的東西。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"시설에 곧 도착합니다. 혹시 모르니 대책을 마련해 둘까요?","JPN":"施設にはまもなく着きます。念のため対策を用意しておきましょうか？","ENG":"We'll arrive at the facility shortly. Should we set up a contingency plan just in case?","TWN":"我們即將抵達設施，需要準備一些對策嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래, 좋다. 내부 인원들에게 비상 태세 발령하고 대기하라 해 둬.","JPN":"そうだな。内部の人間に非常事態を発令して待機するようにと伝えろ。","ENG":"That sounds like a good idea. Have everyone inside on standby.","TWN":"好，發布緊急狀態，叫大家待命。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"비상 태세란 말씀은…….","JPN":"非常事態ということは……","ENG":"By standby, you don't mean…","TWN":"緊急狀態……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"설마 실험체들도 쓰시려는 겁니까?","JPN":"まさか実験体も使うつもりですか？","ENG":"You're not going to use the test subjects, are you?","TWN":"意思是連實驗體也殺無赦嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"왜, 아니면 네가 그 사채꾼을 막을 건가?","JPN":"ダメか？　それとも、お前があの闇金業者を止めるのか？","ENG":"Why not? Did you want to stop that loan shark yourself?","TWN":"怎麼？有意見嗎？還是你打得過那個放高利貸的？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"그, 그런 뜻으로 한 말은 아니고…….","JPN":"い、いや、そういう意味ではありませんが……","ENG":"T-that's not what I meant…","TWN":"我不是那個意思……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"이쯤 말했으면 적당히 알아듣고 운전이나 잘해. 강화복 값도 못하는 쓸모없는 놈이.","JPN":"わかったならさっさと運転に集中しろ。\\nその強化服は誰が支給してやったと思ってるんだ、無能め。","ENG":"Then just shut up and keep your eyes on the road. Don't make me regret wasting my money on your power suit.","TWN":"我說什麼你就照做，好好開車就好，強化服給你穿根本就是浪費！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"넵! 죄송합니다! 주의하겠습니다, 대표님!","JPN":"はい！　申し訳ございません！　気を付けます、代表！","ENG":"Yes, sir! My apologies! I'll be more careful next time, sir!","TWN":"是！很抱歉，代表！我會注意！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"호라이즌……. 너 같이 무식한 것들은 자기가 누구한테 덤볐는지도 모르지.","JPN":"ホライズン……貴様みたいな無知なやつは、誰に歯向かったのか自覚してないだろうな。","ENG":"Horizon… Halfwits like you never realize whom you're messing with till it's too late.","TWN":"地平線……像你這種不用腦的傢伙，肯定不知道你招惹到誰吧！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하지만 넌 지금 감당 못할 짓을 저지른 거야.","JPN":"貴様は今、手に負えないことをやらかしたんだ。","ENG":"You're going to regret this.","TWN":"你會對你現在的行為感到後悔的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이동 중인 차량의 식별신호 및 차종 분석 완료.","JPN":"移動車両の識別信号および車種分析完了。","ENG":"Vehicle signature and type identified.","TWN":"移動中車輛的識別信號和車種分析完畢。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제프티 바이오테크 소속을 확인했습니다. 추격 개시.","JPN":"ジェフティ・バイオテック所属であることを確認しました。追撃開始。","ENG":"Affiliation with Jehuty Biotech confirmed. Commencing pursuit.","TWN":"確定屬於傑夫堤生物科技，開始追擊。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};